import React, { useState } from 'react';
import { PageHeader, Modal } from '../../components/UI';

// ============================================================
// 📁 VIDEOS LOCALES — mets tes .mp4 dans src/assets/videos/
// Puis décommente les imports ci-dessous
// ============================================================

// --- BICEPS ---
// import vidBiceps         from '../../assets/videos/machine-bicep-curl.mp4';
// import vidBarbelCurl     from '../../assets/videos/barbell-curl.mp4';
// import vidDumbbellCurl   from '../../assets/videos/dumbbell-curl.mp4';
// import vidHammerCurl     from '../../assets/videos/hammer-curl.mp4';
// import vidConcentrCurl   from '../../assets/videos/concentration-curl.mp4';

// --- TRICEPS ---
// import vidTriceps        from '../../assets/videos/cable-rope-pushdown.mp4';
// import vidDips           from '../../assets/videos/dips.mp4';
// import vidExtNuque       from '../../assets/videos/overhead-tricep-extension.mp4';
// import vidPushdown       from '../../assets/videos/cable-rope-pushdown.mp4';
// import vidDiamond        from '../../assets/videos/diamond-push-up.mp4';

// --- PECTORAUX ---
// import vidPec            from '../../assets/videos/machine-chest-press.mp4';
// import vidBenchPress     from '../../assets/videos/barbell-bench-press.mp4';
// import vidIncline        from '../../assets/videos/barbell-incline-bench-press.mp4';
// import vidFly            from '../../assets/videos/dumbbell-fly.mp4';
// import vidCrossover      from '../../assets/videos/cable-crossover.mp4';

// --- DOS ---
// import vidDos            from '../../assets/videos/machine-pulldown.mp4';
// import vidPullUp         from '../../assets/videos/pull-up.mp4';
// import vidRowingBarre    from '../../assets/videos/barbell-row.mp4';
// import vidTirage         from '../../assets/videos/machine-pulldown.mp4';
// import vidDeadlift       from '../../assets/videos/barbell-deadlift.mp4';

// --- ÉPAULES ---
// import vidEpaules        from '../../assets/videos/machine-shoulder-press.mp4';
// import vidMilPress       from '../../assets/videos/barbell-overhead-press.mp4';
// import vidLatRaise       from '../../assets/videos/dumbbell-lateral-raise.mp4';
// import vidReverseFly     from '../../assets/videos/dumbbell-reverse-fly.mp4';
// import vidShrug          from '../../assets/videos/dumbbell-shrug.mp4';

// --- JAMBES ---
// import vidJambes         from '../../assets/videos/machine-leg-press.mp4';
// import vidSquat          from '../../assets/videos/barbell-squat.mp4';
// import vidLegPress       from '../../assets/videos/machine-leg-press.mp4';
// import vidLunge          from '../../assets/videos/bodyweight-lunge.mp4';
// import vidLegExt         from '../../assets/videos/machine-leg-extension.mp4';
// import vidLegCurl        from '../../assets/videos/seated-leg-curl.mp4';

// --- ABDOMINAUX ---
// import vidAbs            from '../../assets/videos/crunch.mp4';
// import vidPlank          from '../../assets/videos/plank.mp4';
// import vidCrunchCable    from '../../assets/videos/cable-crunch.mp4';
// import vidLegRaise       from '../../assets/videos/hanging-leg-raise.mp4';
// import vidRussian        from '../../assets/videos/russian-twist.mp4';

// --- MOLLETS ---
// import vidMollets        from '../../assets/videos/standing-calf-raise.mp4';
// import vidCalfStand      from '../../assets/videos/standing-calf-raise.mp4';
// import vidCalfSit        from '../../assets/videos/seated-calf-raise.mp4';

// ============================================================
// 🔗 URLs MuscleWiki (fallback tant que tu n'as pas les fichiers)
// Ces URLs fonctionnent depuis un navigateur
// ============================================================
const MW = 'https://media.musclewiki.com/media/uploads/videos/branded/';

const V = {
  // Groupes musculaires
  biceps:       `${MW}male-Machine-machine-bicep-curl-front.mp4`,
  triceps:      `${MW}male-cables-cable-rope-pushdown-front.mp4`,
  pec:          `${MW}male-Machine-machine-chest-press-front.mp4`,
  dos:          `${MW}male-Machine-machine-pulldown-front.mp4`,
  epaules:      `${MW}male-Machine-machine-shoulder-press-front.mp4`,
  jambes:       `${MW}male-Machine-machine-leg-press-front.mp4`,
  abs:          `${MW}male-bodyweight-crunch-front.mp4`,
  mollets:      `${MW}male-bodyweight-standing-calf-raise-front.mp4`,
  // Biceps
  barbelCurl:   `${MW}male-Barbell-barbell-curl-front.mp4`,
  dumbbellCurl: `${MW}male-Dumbbells-dumbbell-curl-front.mp4`,
  hammerCurl:   `${MW}male-Dumbbells-dumbbell-hammer-curl-front.mp4`,
  concCurl:     `${MW}male-Dumbbells-dumbbell-concentration-curl-front.mp4`,
  // Triceps
  dips:         `${MW}male-Bodyweight-parralel-bar-dips-front.mp4`,
  extNuque:     `${MW}male-Dumbbells-dumbbell-overhead-tricep-extension-front.mp4`,
  pushdown:     `${MW}male-cables-cable-rope-pushdown-front.mp4`,
  diamond:      `${MW}male-Bodyweight-diamond-push-up-front.mp4`,
  // Pectoraux
  benchPress:   `${MW}male-Barbell-barbell-bench-press-front.mp4`,
  incline:      `${MW}male-Barbell-barbell-incline-bench-press-front.mp4`,
  fly:          `${MW}male-Dumbbells-dumbbell-fly-front.mp4`,
  crossover:    `${MW}male-cables-cable-crossover-front.mp4`,
  // Dos
  pullUp:       `${MW}male-Bodyweight-pull-up-front.mp4`,
  rowingBarre:  `${MW}male-Barbell-barbell-row-front.mp4`,
  tirage:       `${MW}male-Machine-machine-pulldown-front.mp4`,
  deadlift:     `${MW}male-Barbell-barbell-deadlift-front.mp4`,
  // Épaules
  milPress:     `${MW}male-Barbell-barbell-overhead-press-front.mp4`,
  latRaise:     `${MW}male-Dumbbells-dumbbell-lateral-raise-front.mp4`,
  reverseFly:   `${MW}male-Dumbbells-dumbbell-reverse-fly-front.mp4`,
  shrug:        `${MW}male-Dumbbells-dumbbell-shrug-front.mp4`,
  // Jambes
  squat:        `${MW}male-Barbell-barbell-squat-front.mp4`,
  legPress:     `${MW}male-Machine-machine-leg-press-front.mp4`,
  lunge:        `${MW}male-Bodyweight-bodyweight-lunge-front.mp4`,
  legExt:       `${MW}male-Machine-machine-leg-extension-front.mp4`,
  legCurl:      `${MW}male-Machine-seated-leg-curl-front.mp4`,
  // Abdos
  plank:        `${MW}male-Bodyweight-plank-front.mp4`,
  crunchCable:  `${MW}male-cables-cable-crunch-front.mp4`,
  legRaise:     `${MW}male-Bodyweight-hanging-leg-raise-front.mp4`,
  russian:      `${MW}male-Bodyweight-russian-twist-front.mp4`,
  // Mollets
  calfStand:    `${MW}male-Bodyweight-standing-calf-raise-front.mp4`,
  calfSit:      `${MW}male-Machine-machine-seated-calf-raise-front.mp4`,
};

// ============================================================
// 📌 Quand tu as tes fichiers locaux, remplace par ex:
//   barbelCurl: vidBarbelCurl,
//   dips: vidDips,
//   etc.
// ============================================================

const muscles = [
  {
    id: 1, nom: 'Biceps', icon: 'bi-lightning-charge', zone: 'Bras',
    video: V.biceps,
    exercices: [
      { nom: 'Curl barre',           series: '4×10', video: V.barbelCurl,   desc: 'Debout, barre en supination. Fléchir les coudes jusqu\'à la hauteur des épaules sans bouger les coudes.' },
      { nom: 'Curl haltères alternés', series: '3×12', video: V.dumbbellCurl, desc: 'Alterner gauche-droite en contrôlant la descente. Tourner le poignet en haut du mouvement.' },
      { nom: 'Curl marteau',         series: '3×12', video: V.hammerCurl,   desc: 'Prise neutre (pouce vers le haut). Cible aussi le brachial et l\'avant-bras.' },
      { nom: 'Curl concentré',       series: '3×15', video: V.concCurl,     desc: 'Assis, coude appuyé sur la cuisse. Excellent pour le pic du biceps.' },
    ]
  },
  {
    id: 2, nom: 'Triceps', icon: 'bi-lightning', zone: 'Bras',
    video: V.triceps,
    exercices: [
      { nom: 'Dips',             series: '4×12', video: V.dips,     desc: 'Corps vertical, coudes près du corps. Plus efficace avec lest quand maîtrisé.' },
      { nom: 'Extension nuque',  series: '3×12', video: V.extNuque, desc: 'Haltère ou barre EZ derrière la tête. Cible le chef long du triceps.' },
      { nom: 'Pushdown câble',   series: '4×15', video: V.pushdown, desc: 'Câble haute poulie, coudes fixes. Excellent pour la finition et le pump.' },
      { nom: 'Pompes diamant',   series: '3×15', video: V.diamond,  desc: 'Mains en triangle sous le sternum. Variante au poids du corps très efficace.' },
    ]
  },
  {
    id: 3, nom: 'Pectoraux', icon: 'bi-person-arms-up', zone: 'Buste',
    video: V.pec,
    exercices: [
      { nom: 'Développé couché',   series: '5×8',  video: V.benchPress, desc: 'Le roi des exercices de poitrine. Descendre la barre jusqu\'à effleurer le sternum.' },
      { nom: 'Développé incliné',  series: '4×10', video: V.incline,    desc: 'Banc à 30-45°. Cible le faisceau supérieur pour un pec plus complet.' },
      { nom: 'Écarté haltères',    series: '3×12', video: V.fly,        desc: 'Légère flexion des coudes. Mouvement d\'isolation, descente lente et contrôlée.' },
      { nom: 'Crossover câbles',   series: '3×15', video: V.crossover,  desc: 'Croisement des mains en bas. Étirement maximal du grand pectoral.' },
    ]
  },
  {
    id: 4, nom: 'Dos', icon: 'bi-arrows-expand-vertical', zone: 'Dos',
    video: V.dos,
    exercices: [
      { nom: 'Tractions',          series: '4×12',  video: V.pullUp,      desc: 'Prise large pronation. Le squat du dos. Ajouter du lest progressivement.' },
      { nom: 'Rowing barre',       series: '4×10', video: V.rowingBarre, desc: 'Tronc parallèle au sol, tirer vers le nombril. Excellent pour l\'épaisseur.' },
      { nom: 'Tirage poulie haute',series: '3×12', video: V.tirage,      desc: 'Tirer vers le haut du sternum. Alternatif aux tractions pour les débutants.' },
      { nom: 'Soulevé de terre',   series: '4×6',  video: V.deadlift,    desc: 'Le mouvement roi. Dos droit, gainage total, poussée des talons dans le sol.' },
    ]
  },
  {
    id: 5, nom: 'Épaules', icon: 'bi-award', zone: 'Épaules',
    video: V.epaules,
    exercices: [
      { nom: 'Développé militaire', series: '4×10', video: V.milPress,   desc: 'Debout ou assis, barre ou haltères. Cible le faisceau antérieur en priorité.' },
      { nom: 'Élévation latérale',  series: '4×15', video: V.latRaise,   desc: 'Petits poids, coudes légèrement fléchis. Faisceau latéral = épaules larges.' },
      { nom: 'Oiseau (Rear delt)',  series: '3×15', video: V.reverseFly, desc: 'Tronc penché, bras en croix. Indispensable pour équilibrer posture et force.' },
      { nom: 'Shrugs',              series: '4×12', video: V.shrug,      desc: 'Haussement d\'épaules avec haltères ou barre. Cible les trapèzes supérieurs.' },
    ]
  },
  {
    id: 6, nom: 'Jambes', icon: 'bi-activity', zone: 'Jambes',
    video: V.jambes,
    exercices: [
      { nom: 'Squat',          series: '4×12',  video: V.squat,   desc: 'Le roi des exercices. Descendre cuisses parallèles, dos droit, genoux dans l\'axe.' },
      { nom: 'Presse à cuisses',series: '4×12', video: V.legPress,desc: 'Pieds hauts = ischios/fessiers. Pieds bas = quadriceps. Contrôler la montée.' },
      { nom: 'Fentes marchées', series: '3×10', video: V.lunge,   desc: 'Chaque jambe. Grand pas, genou avant à 90°. Excellent pour l\'équilibre.' },
      { nom: 'Leg extension',   series: '3×15', video: V.legExt,  desc: 'Isolation quadriceps. Finition en fin de séance pour le pump.' },
      { nom: 'Leg curl',        series: '3×15', video: V.legCurl, desc: 'Isolation ischios-jambiers. Ne pas négliger les muscles postérieurs.' },
    ]
  },
  {
    id: 7, nom: 'Abdominaux', icon: 'bi-grid-3x3', zone: 'Core',
    video: V.abs,
    exercices: [
      { nom: 'Gainage planche',  series: '4×60s', video: V.plank,       desc: 'Corps aligné, contractez abdos et fessiers. Base indispensable du gainage.' },
      { nom: 'Crunch câble',     series: '4×12',  video: V.crunchCable, desc: 'Plus efficace que le crunch classique car résistance constante sur tout le mouvement.' },
      { nom: 'Relevé de jambes', series: '3×15',  video: V.legRaise,    desc: 'Suspendu ou allongé. Cible le bas du ventre (droit inférieur).' },
      { nom: 'Russian twist',    series: '3×12',  video: V.russian,     desc: 'Avec médecine-ball ou haltère. Cible les obliques et la rotation du tronc.' },
    ]
  },
  {
    id: 8, nom: 'Mollets', icon: 'bi-arrow-up-circle', zone: 'Jambes',
    video: V.mollets,
    exercices: [
      { nom: 'Extensions mollets debout', series: '5×12', video: V.calfStand, desc: 'Amplitude complète, tenir 1s en haut. Les mollets récupèrent vite, volume élevé.' },
      { nom: 'Extensions assis',          series: '4×12', video: V.calfSit,   desc: 'Cible le soléaire (muscle profond). Indispensable pour des mollets complets.' },
    ]
  },
];

// ============================================================
// Composant vidéo — key={src} force le rechargement au changement
// ============================================================
function ExerciseVideo({ src, style = {} }) {
  return (
    <video
      key={src}
      src={src}
      autoPlay
      loop
      muted
      playsInline
      style={{ width: '100%', height: '100%', objectFit: 'cover', display: 'block', ...style }}
    />
  );
}

export default function Musculation() {
  const [selected, setSelected] = useState(null);
  const [activeExo, setActiveExo] = useState(null);

  const openMuscle = (m) => { setSelected(m); setActiveExo(null); };
  const displayedVideo = activeExo?.video ?? selected?.video;

  return (
    <div>
      <PageHeader eyebrow="Guide d'entraînement" title="Exercices par" accent="Groupe Musculaire" />

      <div style={{ padding: '16px 28px 8px', fontSize: 13, color: 'var(--text-muted)' }}>
        Cliquez sur un groupe musculaire pour voir les exercices recommandés, les séries et les conseils techniques.
      </div>

      {/* Grille muscles */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4,1fr)', gap: 14, padding: '12px 28px 32px' }}>
        {muscles.map(m => (
          <div key={m.id} className="fz-card hoverable" style={{ overflow: 'hidden', padding: 0 }} onClick={() => openMuscle(m)}>
            <div className="muscle-img-placeholder" style={{ position: 'relative', overflow: 'hidden' }}>
              <ExerciseVideo src={m.video} />
            </div>
            <div style={{ padding: '12px 14px' }}>
              <div style={{ fontFamily: 'var(--font-heading)', fontSize: 16, fontWeight: 700, marginBottom: 2 }}>{m.nom}</div>
              <div style={{ fontSize: 10, color: 'var(--text-dim)', marginBottom: 8 }}>{m.zone} · {m.exercices.length} exercices</div>
              {m.exercices.slice(0, 2).map(e => (
                <div key={e.nom} style={{ fontSize: 11, color: 'var(--text-muted)', marginBottom: 2 }}>
                  <i className="bi bi-chevron-right me-1" style={{ fontSize: 9, color: 'var(--red)' }}></i>{e.nom}
                </div>
              ))}
              <div style={{ fontSize: 10, color: 'var(--text-dim)', marginTop: 4 }}>+{m.exercices.length - 2} autres...</div>
            </div>
          </div>
        ))}
      </div>

      {/* Modale */}
      <Modal show={!!selected} title={selected?.nom} onClose={() => setSelected(null)} size="lg">
        {selected && (
          <div>
            {/* Badges */}
            <div style={{ display: 'flex', gap: 12, marginBottom: 16, flexWrap: 'wrap', alignItems: 'center' }}>
              <span className="fz-badge type">{selected.zone}</span>
              <span style={{ fontSize: 12, color: 'var(--text-muted)' }}>{selected.exercices.length} exercices</span>
              {activeExo && (
                <span
                  onClick={() => setActiveExo(null)}
                  style={{ fontSize: 11, color: 'var(--red)', marginLeft: 'auto', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: 4 }}
                >
                  <i className="bi bi-arrow-left" style={{ fontSize: 10 }}></i> Groupe musculaire
                </span>
              )}
            </div>

            {/* Vidéo principale */}
            <div style={{ marginBottom: 20, borderRadius: 10, border: '1px solid var(--border)', height: 250, overflow: 'hidden', background: '#0d0d0d', position: 'relative' }}>
              <ExerciseVideo src={displayedVideo} style={{ objectFit: 'contain', background: '#0d0d0d' }} />
              {/* Overlay nom exercice actif */}
              {activeExo && (
                <div style={{
                  position: 'absolute', bottom: 0, left: 0, right: 0,
                  background: 'linear-gradient(transparent, rgba(0,0,0,0.85))',
                  padding: '30px 16px 12px',
                  fontFamily: 'var(--font-heading)', fontSize: 14, fontWeight: 700, color: '#fff',
                  display: 'flex', alignItems: 'center', gap: 8
                }}>
                  <i className="bi bi-play-circle-fill" style={{ color: 'var(--red)', fontSize: 16 }}></i>
                  {activeExo.nom}
                </div>
              )}
            </div>

            {/* Liste exercices cliquables */}
            <div style={{ display: 'flex', flexDirection: 'column', gap: 10 }}>
              {selected.exercices.map((e) => {
                const isActive = activeExo?.nom === e.nom;
                return (
                  <div
                    key={e.nom}
                    onClick={() => setActiveExo(isActive ? null : e)}
                    style={{
                      background: isActive ? 'rgba(220,38,38,0.08)' : 'var(--surface2)',
                      borderRadius: 10,
                      padding: '14px 16px',
                      borderLeft: `3px solid var(--red)`,
                      cursor: 'pointer',
                      transition: 'all 0.15s ease',
                      outline: isActive ? '1px solid rgba(220,38,38,0.3)' : '1px solid transparent',
                    }}
                  >
                    <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 6 }}>
                      <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
                        {/* Bouton play/pause */}
                        <div style={{
                          width: 26, height: 26, borderRadius: '50%',
                          background: isActive ? 'var(--red)' : 'rgba(255,255,255,0.06)',
                          border: isActive ? 'none' : '1px solid rgba(255,255,255,0.1)',
                          display: 'flex', alignItems: 'center', justifyContent: 'center',
                          flexShrink: 0, transition: 'all 0.15s'
                        }}>
                          <i
                            className={`bi bi-${isActive ? 'pause-fill' : 'play-fill'}`}
                            style={{ fontSize: 10, color: isActive ? '#fff' : 'var(--red)', marginLeft: isActive ? 0 : 1 }}
                          />
                        </div>
                        <div style={{ fontFamily: 'var(--font-heading)', fontSize: 15, fontWeight: 700, color: isActive ? '#fff' : 'inherit' }}>
                          {e.nom}
                        </div>
                      </div>
                      <span className="fz-badge type">{e.series}</span>
                    </div>
                    <p style={{ fontSize: 12, color: 'var(--text-muted)', margin: 0, lineHeight: 1.6, paddingLeft: 36 }}>
                      {e.desc}
                    </p>
                  </div>
                );
              })}
            </div>
          </div>
        )}
      </Modal>
    </div>
  );
}
